import { useState, useEffect } from "react";
import { useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { login } from "../authReducer";
import bcrypt from "bcryptjs";

function Register() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [role, setRole] = useState("student");
  const [adminCount, setAdminCount] = useState(0); // Состояние для подсчета админов

  // Проверяем количество админов при загрузке компонента
  useEffect(() => {
    fetch("http://localhost:3001/users?role=admin")
      .then((res) => res.json())
      .then((data) => setAdminCount(data.length))
      .catch((error) => console.error("Error fetching admins:", error));
  }, []);

  async function handleRegister(e) {
    e.preventDefault();

    // Проверка количества админов перед регистрацией (лимит 2)
    if (role === "admin" && adminCount >= 2) {
      alert("Only two admins are allowed!");
      return;
    }

    try {
      const hashedPassword = await bcrypt.hash(password, 10);
      const newUser = { email, password: hashedPassword, name, role };

      const response = await fetch("http://localhost:3001/users", {
        method: "POST",
        headers: { "Content-Type": "application/json" }, // Исправлено "Countent-Type" на "Content-Type"
        body: JSON.stringify(newUser),
      });

      if (response.ok) {
        const user = await response.json();
        dispatch(login(user));
        navigate("/dashboard");
      } else {
        alert("Registration failed");
      }
    } catch (error) {
      console.error("Fetch error:", error);
      alert("Failed to register due to a network error.");
    }
  }

  return (
    <form onSubmit={handleRegister}>
      <input
        type="text"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />
      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        required
      />
      <select value={role} onChange={(e) => setRole(e.target.value)}>
        <option value="student">Student</option>
        <option value="teacher">Teacher</option>
        {adminCount < 2 && <option value="admin">Admin</option>} {/* Опция доступна, если админов меньше 2 */}
      </select>
      {adminCount >= 2 && <p style={{ color: "red" }}>Admin limit reached (max 2).</p>} {/* Сообщение при лимите */}
      <button type="submit">Register</button>
    </form>
  );
}

export default Register;
